import React, { useState } from 'react';

const links = [
  { label: 'Home', href: '#Introduction' },
  { label: 'About Me', href: '#About-Me' },
  { label: 'Education', href: '#Education' },
  { label: 'Experience', href: '#Experience' },
  { label: 'Skills', href: '#Skills' },
  { label: 'My Projects', href: '#Projects' },
  { label: 'Contact', href: '#Contact' },
];

const Navbar = () => {
  const [hovered, setHovered] = useState(null);
  return (
    <nav
      id="navbar"
      className="fixed top-0 left-0 w-full z-50 flex gap-8 px-6 py-4 shadow-lg"
      style={{ background: '#335765' }}
    >
      {links.map((link) => (
        <a
          key={link.href}
          href={link.href}
          onMouseEnter={() => setHovered(link.href)}
          onMouseLeave={() => setHovered(null)}
          className="font-bold text-base no-underline transition-all duration-300 inline-block"
          style={{
            color: hovered === link.href ? 'rgb(180,180,180)' : '#ffffff',
            transform: hovered === link.href ? 'translateY(-2px)' : 'translateY(0)',
            textDecoration: 'none',
          }}
        >
          {link.label}
        </a>
      ))}
    </nav>
  );
};

export default Navbar;
